// src/app.js
const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

// src/modules/projects/routes.js
const express = require('express');
const { sendError } = require('../../lib/errors');
const projectsService = require('./service');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Name is required');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    if (error.code === 'DUPLICATE_PROJECT') {
      return sendError(res, 409, 'DUPLICATE_PROJECT', 'Project already exists');
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function createProject(name) {
  if (projectsStore.some(project => project.name === name)) {
    return null;
  }
  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  createProject,
};

// src/modules/members/routes.js
const express = require('express');
const { sendError } = require('../../lib/errors');
const membersService = require('./service');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'UserId and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

async function addMember(projectId, userId, role) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const member = { id: randomUUID(), projectId, userId, role };
  // Assuming a simple in-memory store for members
  project.members = project.members || [];
  project.members.push(member);
  return member;
}

module.exports = {
  addMember,
};

// src/modules/tasks/routes.js
const express = require('express');
const { sendError } = require('../../lib/errors');
const tasksService = require('./service');

const router = express.Router();

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Description is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, description);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getTasks(req.params.projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

async function createTask(projectId, description) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = { id: randomUUID(), projectId, description, status: 'todo' };
  // Assuming a simple in-memory store for tasks
  project.tasks = project.tasks || [];
  project.tasks.push(task);
  return task;
}

async function getTasks(projectId, status) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  let tasks = project.tasks || [];
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

async function updateTaskStatus(projectId, taskId, status) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = {
  createTask,
  getTasks,
  updateTaskStatus,
};

// src/modules/comments/routes.js
const express = require('express');
const { sendError } = require('../../lib/errors');
const commentsService = require('./service');

const router = express.Router();

router.post('/', async (req, res) => {
  const { content } = req.body;
  if (!content) {
    return sendError(res, 400, 'INVALID_INPUT', 'Content is required');
  }
  try {
    const comment = await commentsService.addComment(req.params.projectId, req.params.taskId, content);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');

async function addComment(projectId, taskId, content) {
  const task = await tasksService.getTasks(projectId).find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  const comment = { id: randomUUID(), taskId, projectId, content };
  // Assuming a simple in-memory store for comments
  task.comments = task.comments || [];
  task.comments.push(comment);
  return comment;
}

module.exports = {
  addComment,
};

